class Solution:
    def rob(self, nums: List[int], colors: List[int]) -> int:
        n = len(nums)
        dp_take = nums[0]
        dp_skip = 0
        for i in range(1, n):
            if colors[i] == colors[i - 1]:
                new_take = nums[i] + dp_skip
            else:
                new_take = nums[i] + max(dp_skip, dp_take)
            new_skip = max(dp_take, dp_skip)
            dp_take, dp_skip = new_take, new_skip
        return max(dp_take, dp_skip)

