var rob = function(nums, colors) {
    const n = nums.length;
    let dpTake = nums[0];
    let dpSkip = 0;
    for (let i = 1; i < n; i++) {
        let newTake;
        if (colors[i] === colors[i - 1]) {
            newTake = nums[i] + dpSkip;
        } else {
            newTake = nums[i] + Math.max(dpSkip, dpTake);
        }
        const newSkip = Math.max(dpTake, dpSkip);
        dpTake = newTake;
        dpSkip = newSkip;
    }
    return Math.max(dpTake, dpSkip);
};
